-- Tail UI Library Executor Bundle
-- Generated by tools/build_executor_bundle.ps1

local __modules = {}
local __cache = {}

local function __require(name)
	local cached = __cache[name]
	if cached ~= nil then
		return cached
	end
	local loader = __modules[name]
	if not loader then
		error("[TailUI Bundle] module not found: " .. tostring(name), 2)
	end
	local value = loader()
	__cache[name] = value
	return value
end

__modules["Core.Logger"] = function()
local HttpService = game:GetService("HttpService")

local Logger = {}
Logger.__index = Logger

function Logger.new(options)
	options = options or {}

	local self = setmetatable({}, Logger)
	self.prefix = options.prefix or "[TailUI]"
	self.maxEntries = options.maxEntries or 300
	self.entries = {}
	self.onEntry = options.onEntry

	return self
end

function Logger:_push(level, message, context)
	local entry = {
		level = level,
		message = tostring(message),
		context = context,
		timestamp = os.time(),
	}

	table.insert(self.entries, entry)
	if #self.entries > self.maxEntries then
		table.remove(self.entries, 1)
	end

	local line = ("%s [%s] %s"):format(self.prefix, level, entry.message)
	if level == "ERROR" or level == "WARN" then
		warn(line)
	else
		print(line)
	end

	if context ~= nil then
		local ok, encoded = pcall(function()
			return HttpService:JSONEncode(context)
		end)
		if ok then
			print(("%s [CTX] %s"):format(self.prefix, encoded))
		end
	end

	if self.onEntry then
		pcall(self.onEntry, entry)
	end

	return entry
end

function Logger:debug(message, context)
	return self:_push("DEBUG", message, context)
end

function Logger:info(message, context)
	return self:_push("INFO", message, context)
end

function Logger:warn(message, context)
	return self:_push("WARN", message, context)
end

function Logger:error(message, context)
	return self:_push("ERROR", message, context)
end

function Logger:getEntries()
	return self.entries
end

return Logger
end

__modules["Core.SafeCall"] = function()
local SafeCall = {}
SafeCall.__index = SafeCall

function SafeCall.new(logger, uiReporter)
	local self = setmetatable({}, SafeCall)
	self.logger = logger
	self.uiReporter = uiReporter
	return self
end

function SafeCall:execute(scope, fn, ...)
	if type(fn) ~= "function" then
		return false, "safe execution received a non-function"
	end

	local packed = table.pack(...)
	local ok, result = xpcall(function()
		return fn(table.unpack(packed, 1, packed.n))
	end, function(err)
		return debug.traceback(tostring(err), 2)
	end)

	if ok then
		return true, result
	end

	local report = ("Scope '%s' failed: %s"):format(tostring(scope), tostring(result))
	if self.logger then
		self.logger:error(report)
	end

	if self.uiReporter then
		pcall(self.uiReporter, scope, result)
	end

	return false, result
end

function SafeCall:wrap(scope, fn, onFailure)
	return function(...)
		local ok, result = self:execute(scope, fn, ...)
		if not ok and onFailure then
			pcall(onFailure, result)
		end
		return ok, result
	end
end

return SafeCall
end

__modules["Core.FileSystem"] = function()
local HttpService = game:GetService("HttpService")

local FileSystem = {}
FileSystem.__index = FileSystem

local function readGlobal(name)
	local env = nil
	if getfenv then
		env = getfenv()
	end
	if env and env[name] ~= nil then
		return env[name]
	end
	return _G[name]
end

local function normalizePath(path)
	path = tostring(path or "")
	path = path:gsub("\\", "/")
	path = path:gsub("/+", "/")
	return path
end

function FileSystem.new(logger)
	local self = setmetatable({}, FileSystem)
	self.logger = logger
	return self
end

function FileSystem:supportsIO()
	return type(readGlobal("readfile")) == "function"
		and type(readGlobal("writefile")) == "function"
		and type(readGlobal("makefolder")) == "function"
end

function FileSystem:join(...)
	local items = table.pack(...)
	local out = {}
	for i = 1, items.n do
		local token = tostring(items[i])
		if token ~= "" then
			table.insert(out, token)
		end
	end
	return normalizePath(table.concat(out, "/"))
end

function FileSystem:exists(path)
	path = normalizePath(path)
	local isfile = readGlobal("isfile")
	local isfolder = readGlobal("isfolder")

	if type(isfile) == "function" then
		local okFile, fileExists = pcall(isfile, path)
		if okFile and fileExists then
			return true
		end
	end

	if type(isfolder) == "function" then
		local okFolder, folderExists = pcall(isfolder, path)
		if okFolder and folderExists then
			return true
		end
	end

	return false
end

function FileSystem:isFolder(path)
	local isfolder = readGlobal("isfolder")
	path = normalizePath(path)
	if type(isfolder) ~= "function" then
		return false
	end
	local ok, result = pcall(isfolder, path)
	return ok and result == true
end

function FileSystem:ensureFolder(path)
	path = normalizePath(path)
	local makefolder = readGlobal("makefolder")
	local isfolder = readGlobal("isfolder")

	if type(makefolder) ~= "function" or type(isfolder) ~= "function" then
		if self.logger then
			self.logger:warn("makefolder/isfolder not available in this executor", { path = path })
		end
		return false
	end

	local current = ""
	for segment in path:gmatch("[^/]+") do
		current = current == "" and segment or (current .. "/" .. segment)
		local okCheck, exists = pcall(isfolder, current)
		if not okCheck or not exists then
			local okCreate, createErr = pcall(makefolder, current)
			if not okCreate then
				if self.logger then
					self.logger:error("failed to create folder", { path = current, error = tostring(createErr) })
				end
				return false
			end
		end
	end

	return true
end

function FileSystem:read(path, defaultValue)
	path = normalizePath(path)
	local readfile = readGlobal("readfile")
	local isfile = readGlobal("isfile")

	if type(readfile) ~= "function" or type(isfile) ~= "function" then
		return defaultValue
	end

	local okExists, exists = pcall(isfile, path)
	if not okExists or not exists then
		return defaultValue
	end

	local okRead, data = pcall(readfile, path)
	if okRead then
		return data
	end

	if self.logger then
		self.logger:error("failed to read file", { path = path, error = tostring(data) })
	end
	return defaultValue
end

function FileSystem:write(path, content)
	path = normalizePath(path)
	content = tostring(content or "")
	local writefile = readGlobal("writefile")
	if type(writefile) ~= "function" then
		if self.logger then
			self.logger:warn("writefile not available", { path = path })
		end
		return false
	end

	local folder = path:match("^(.*)/[^/]+$")
	if folder and folder ~= "" then
		self:ensureFolder(folder)
	end

	local okWrite, writeErr = pcall(writefile, path, content)
	if okWrite then
		return true
	end

	if self.logger then
		self.logger:error("failed to write file", { path = path, error = tostring(writeErr) })
	end
	return false
end

function FileSystem:list(path)
	path = normalizePath(path)
	local listfiles = readGlobal("listfiles")
	if type(listfiles) ~= "function" then
		return {}
	end

	local ok, items = pcall(listfiles, path)
	if not ok or type(items) ~= "table" then
		return {}
	end
	return items
end

function FileSystem:readJSON(path, defaultValue)
	local raw = self:read(path, nil)
	if raw == nil then
		return defaultValue
	end

	local ok, decoded = pcall(function()
		return HttpService:JSONDecode(raw)
	end)
	if ok then
		return decoded
	end

	if self.logger then
		self.logger:warn("json decode failed", { path = path, error = tostring(decoded) })
	end
	return defaultValue
end

function FileSystem:writeJSON(path, data)
	local ok, encoded = pcall(function()
		return HttpService:JSONEncode(data)
	end)
	if not ok then
		if self.logger then
			self.logger:error("json encode failed", { path = path, error = tostring(encoded) })
		end
		return false
	end
	return self:write(path, encoded)
end

return FileSystem
end

__modules["Core.ConfigManager"] = function()
local DEFAULT_CONFIG = {
	internal = {
		version = "1.0.0",
		searchEnabled = true,
		showLoading = true,
		mobileBreakpoint = 840,
	},
	window = {
		title = "Tail UI",
		subtitle = "Safari inspired",
		size = { width = 780, height = 520 },
		minimumSize = { width = 520, height = 360 },
		resizable = true,
		draggable = true,
	},
	theme = {
		active = "safari-ocean",
		autoLoadDiskThemes = true,
	},
	performance = {
		maxLogs = 300,
		isolation = true,
	},
	icons = {
		preferred = { "lucide" },
	},
	fonts = {
		default = "ui-sans",
	},
}

local ConfigManager = {}
ConfigManager.__index = ConfigManager

local function deepCopy(value)
	if type(value) ~= "table" then
		return value
	end
	local copy = {}
	for key, child in pairs(value) do
		copy[key] = deepCopy(child)
	end
	return copy
end

local function deepMerge(base, incoming)
	if type(base) ~= "table" then
		return deepCopy(incoming)
	end
	local output = deepCopy(base)
	if type(incoming) ~= "table" then
		return output
	end
	for key, value in pairs(incoming) do
		if type(value) == "table" and type(output[key]) == "table" then
			output[key] = deepMerge(output[key], value)
		else
			output[key] = deepCopy(value)
		end
	end
	return output
end

local function sanitizeHubName(name)
	name = tostring(name or "tail-hub")
	name = name:lower()
	name = name:gsub("[^%w%-_ ]", "")
	name = name:gsub("%s+", "-")
	if name == "" then
		name = "tail-hub"
	end
	return name
end

function ConfigManager.new(fileSystem, logger)
	local self = setmetatable({}, ConfigManager)
	self.fileSystem = fileSystem
	self.logger = logger
	self.defaults = deepCopy(DEFAULT_CONFIG)
	self.paths = nil
	self.hubName = nil
	return self
end

function ConfigManager:getDefaultConfig()
	return deepCopy(self.defaults)
end

function ConfigManager:initialize(hubName, extraDefaults)
	self.hubName = sanitizeHubName(hubName)
	if type(extraDefaults) == "table" then
		self.defaults = deepMerge(self.defaults, extraDefaults)
	end

	local root = self.fileSystem:join("workspace", self.hubName)
	self.paths = {
		root = root,
		bin = self.fileSystem:join(root, "bin"),
		themeRoot = self.fileSystem:join(root, "themes"),
		cache = self.fileSystem:join(root, "cache"),
		logs = self.fileSystem:join(root, "logs"),
		config = self.fileSystem:join(root, "bin", "configurations.config"),
		themeBootstrap = self.fileSystem:join(root, "themes", "initate.lua"),
	}

	self.fileSystem:ensureFolder(self.paths.root)
	self.fileSystem:ensureFolder(self.paths.bin)
	self.fileSystem:ensureFolder(self.paths.themeRoot)
	self.fileSystem:ensureFolder(self.paths.cache)
	self.fileSystem:ensureFolder(self.paths.logs)

	if not self.fileSystem:exists(self.paths.config) then
		self.fileSystem:writeJSON(self.paths.config, self.defaults)
	end

	if not self.fileSystem:exists(self.paths.themeBootstrap) then
		local bootstrap = table.concat({
			"-- Tail UI theme bootstrap",
			"-- Any folder inside ./themes that has a theme.json file will be auto-loaded.",
			"return {",
			"\tversion = '1.0',",
			"\tautoDiscover = true,",
			"}",
			"",
		}, "\n")
		self.fileSystem:write(self.paths.themeBootstrap, bootstrap)
	end

	return self.paths
end

function ConfigManager:getPaths()
	return self.paths
end

function ConfigManager:load()
	local raw = self.fileSystem:readJSON(self.paths.config, {})
	return deepMerge(self.defaults, raw)
end

function ConfigManager:save(config)
	return self.fileSystem:writeJSON(self.paths.config, config)
end

function ConfigManager:getPath(path)
	if type(path) ~= "string" or path == "" then
		return nil
	end
	return self.paths[path]
end

function ConfigManager:listThemeFolders()
	local out = {}
	local listed = self.fileSystem:list(self.paths.themeRoot)
	for _, fullPath in ipairs(listed) do
		local normalized = tostring(fullPath):gsub("\\", "/")
		if self.fileSystem:isFolder(normalized) then
			local name = normalized:match("([^/]+)$")
			if name then
				table.insert(out, {
					name = name,
					path = normalized,
					themeFile = normalized .. "/theme.json",
				})
			end
		end
	end
	return out
end

function ConfigManager:createThemeFolder(name)
	local safeName = sanitizeHubName(name)
	local path = self.fileSystem:join(self.paths.themeRoot, safeName)
	self.fileSystem:ensureFolder(path)
	return path
end

return ConfigManager
end

