__modules["Theme.ThemeManager"] = function()
local ThemeManager = {}
ThemeManager.__index = ThemeManager

local function cloneDeep(value)
	if type(value) ~= "table" then
		return value
	end
	local out = {}
	for key, child in pairs(value) do
		out[key] = cloneDeep(child)
	end
	return out
end

local function mergeDeep(base, incoming)
	if type(base) ~= "table" then
		return cloneDeep(incoming)
	end
	local out = cloneDeep(base)
	if type(incoming) ~= "table" then
		return out
	end
	for key, value in pairs(incoming) do
		if type(value) == "table" and type(out[key]) == "table" then
			out[key] = mergeDeep(out[key], value)
		else
			out[key] = cloneDeep(value)
		end
	end
	return out
end

local function encodeForDisk(value)
	if typeof(value) == "Color3" then
		return {
			__tail_color3 = true,
			r = value.R,
			g = value.G,
			b = value.B,
		}
	end

	if type(value) ~= "table" then
		return value
	end

	local out = {}
	for key, child in pairs(value) do
		out[key] = encodeForDisk(child)
	end
	return out
end

local function decodeFromDisk(value)
	if type(value) ~= "table" then
		return value
	end

	if value.__tail_color3 == true then
		local r = value.r or 0
		local g = value.g or 0
		local b = value.b or 0
		if r > 1 or g > 1 or b > 1 then
			r = math.clamp(r / 255, 0, 1)
			g = math.clamp(g / 255, 0, 1)
			b = math.clamp(b / 255, 0, 1)
		end
		return Color3.new(r, g, b)
	end

	local out = {}
	for key, child in pairs(value) do
		out[key] = decodeFromDisk(child)
	end
	return out
end

function ThemeManager.new(fileSystem, logger, configManager)
	local self = setmetatable({}, ThemeManager)
	self.fileSystem = fileSystem
	self.logger = logger
	self.configManager = configManager
	self.themes = {}
	self.activeName = nil
	self.listeners = {}
	self.nextListenerId = 0
	return self
end

function ThemeManager:register(name, themeData, source)
	if type(name) ~= "string" or name == "" then
		return false, "invalid theme name"
	end
	if type(themeData) ~= "table" then
		return false, "theme must be a table"
	end

	self.themes[name] = {
		data = cloneDeep(themeData),
		source = source or "runtime",
	}
	return true
end

function ThemeManager:registerBuiltins(builtins)
	if type(builtins) ~= "table" then
		return
	end
	for name, theme in pairs(builtins) do
		self:register(name, theme, "builtin")
	end
end

function ThemeManager:createDiskTheme(name, data)
	local themeFolder = self.configManager:createThemeFolder(name)
	local themeFile = self.fileSystem:join(themeFolder, "theme.json")
	return self.fileSystem:writeJSON(themeFile, encodeForDisk(data))
end

function ThemeManager:loadDiskThemes()
	local items = self.configManager:listThemeFolders()
	for _, folder in ipairs(items) do
		local payload = self.fileSystem:readJSON(folder.themeFile, nil)
		if type(payload) == "table" then
			local ok, err = self:register(folder.name, decodeFromDisk(payload), "disk")
			if not ok and self.logger then
				self.logger:warn("failed to register disk theme", {
					theme = folder.name,
					error = err,
				})
			end
		end
	end
end

function ThemeManager:get(name)
	local item = self.themes[name]
	if not item then
		return nil
	end
	return cloneDeep(item.data)
end

function ThemeManager:getActiveName()
	return self.activeName
end

function ThemeManager:getActiveTheme()
	if not self.activeName then
		return nil
	end
	return self:get(self.activeName)
end

function ThemeManager:apply(name, overrides)
	local target = self.themes[name]
	if not target then
		return false, ("theme '%s' not found"):format(tostring(name))
	end

	local theme = target.data
	if type(overrides) == "table" then
		theme = mergeDeep(theme, overrides)
	end

	self.activeName = name
	for _, listener in pairs(self.listeners) do
		pcall(listener, name, cloneDeep(theme))
	end
	return true
end

function ThemeManager:onChanged(callback)
	self.nextListenerId = self.nextListenerId + 1
	local id = self.nextListenerId
	self.listeners[id] = callback
	return {
		Disconnect = function()
			self.listeners[id] = nil
		end,
	}
end

function ThemeManager:list()
	local out = {}
	for name, item in pairs(self.themes) do
		table.insert(out, {
			name = name,
			source = item.source,
		})
	end
	table.sort(out, function(a, b)
		return a.name < b.name
	end)
	return out
end

return ThemeManager
end

__modules["Assets.IconRegistry"] = function()
local DEFAULT_LUCIDE = {
	search = "🔎",
	settings = "⚙",
	close = "●",
	minimize = "◌",
	maximize = "◍",
	tag = "🏷",
	folder = "📁",
	save = "💾",
	theme = "🎨",
	loading = "⌛",
	warning = "⚠",
	success = "✓",
	error = "✕",
}

local IconRegistry = {}
IconRegistry.__index = IconRegistry

function IconRegistry.new(logger)
	local self = setmetatable({}, IconRegistry)
	self.logger = logger
	self.maxExternalLibraries = 5
	self.externalCount = 0
	self.preferredLibraries = { "lucide" }
	self.libraries = {
		lucide = DEFAULT_LUCIDE,
	}
	return self
end

function IconRegistry:setPreferredLibraries(libraries)
	if type(libraries) ~= "table" then
		return
	end
	self.preferredLibraries = libraries
end

function IconRegistry:registerLibrary(name, provider)
	name = tostring(name or "")
	if name == "" or name == "lucide" then
		return false, "library name is invalid or reserved"
	end
	if self.libraries[name] == nil and self.externalCount >= self.maxExternalLibraries then
		return false, "max icon libraries reached (5 external + lucide)"
	end
	if type(provider) ~= "table" and type(provider) ~= "function" then
		return false, "icon provider must be table or function"
	end

	if self.libraries[name] == nil then
		self.externalCount = self.externalCount + 1
	end
	self.libraries[name] = provider
	return true
end

local function resolveFromProvider(provider, iconName)
	if type(provider) == "table" then
		return provider[iconName]
	end
	if type(provider) == "function" then
		return provider(iconName)
	end
	return nil
end

function IconRegistry:resolve(iconName, options)
	options = options or {}
	local libraries = options.libraries or self.preferredLibraries

	for _, libName in ipairs(libraries) do
		local provider = self.libraries[libName]
		local icon = resolveFromProvider(provider, iconName)
		if icon ~= nil then
			return icon
		end
	end

	local fallbackProvider = self.libraries.lucide
	local fallback = resolveFromProvider(fallbackProvider, iconName)
	if fallback ~= nil then
		return fallback
	end

	return options.fallback or "•"
end

function IconRegistry:listLibraries()
	local out = {}
	for name in pairs(self.libraries) do
		table.insert(out, name)
	end
	table.sort(out)
	return out
end

return IconRegistry
end

__modules["Assets.FontRegistry"] = function()
local DEFAULT_FONTS = {
	["ui-sans"] = Enum.Font.Gotham,
	["ui-sans-semibold"] = Enum.Font.GothamSemibold,
	["ui-mono"] = Enum.Font.Code,
	["ui-serif"] = Enum.Font.SourceSans,
	["ui-display"] = Enum.Font.SourceSansBold,
}

local FontRegistry = {}
FontRegistry.__index = FontRegistry

function FontRegistry.new(logger)
	local self = setmetatable({}, FontRegistry)
	self.logger = logger
	self.maxExternalFonts = 5
	self.externalCount = 0
	self.fonts = {}
	for name, font in pairs(DEFAULT_FONTS) do
		self.fonts[name] = font
	end
	return self
end

function FontRegistry:register(name, fontEnum)
	name = tostring(name or "")
	if name == "" then
		return false, "font name cannot be empty"
	end

	if self.fonts[name] == nil and self.externalCount >= self.maxExternalFonts then
		return false, "max external fonts reached (5)"
	end

	if typeof(fontEnum) ~= "EnumItem" or fontEnum.EnumType ~= Enum.Font then
		return false, "font must be Enum.Font"
	end

	if self.fonts[name] == nil then
		self.externalCount = self.externalCount + 1
	end
	self.fonts[name] = fontEnum
	return true
end

function FontRegistry:resolve(name, fallback)
	local font = self.fonts[name]
	if font then
		return font
	end
	if fallback and self.fonts[fallback] then
		return self.fonts[fallback]
	end
	return self.fonts["ui-sans"]
end

function FontRegistry:list()
	local out = {}
	for name in pairs(self.fonts) do
		table.insert(out, name)
	end
	table.sort(out)
	return out
end

return FontRegistry
end

__modules["UI.FuzzySearch"] = function()
local FuzzySearch = {}

local function normalize(text)
	text = tostring(text or ""):lower()
	text = text:gsub("[%c%p]", " ")
	text = text:gsub("%s+", " ")
	text = text:gsub("^%s+", "")
	text = text:gsub("%s+$", "")
	return text
end

local function levenshtein(a, b)
	local lenA = #a
	local lenB = #b
	if lenA == 0 then
		return lenB
	end
	if lenB == 0 then
		return lenA
	end

	local matrix = {}
	for i = 0, lenA do
		matrix[i] = { [0] = i }
	end
	for j = 0, lenB do
		matrix[0][j] = j
	end

	for i = 1, lenA do
		for j = 1, lenB do
			local cost = (a:sub(i, i) == b:sub(j, j)) and 0 or 1
			matrix[i][j] = math.min(
				matrix[i - 1][j] + 1,
				matrix[i][j - 1] + 1,
				matrix[i - 1][j - 1] + cost
			)
		end
	end

	return matrix[lenA][lenB]
end

local function subsequenceScore(query, target)
	local qi = 1
	local score = 0
	for i = 1, #target do
		if target:sub(i, i) == query:sub(qi, qi) then
			score = score + 1
			qi = qi + 1
			if qi > #query then
				break
			end
		end
	end
	if qi <= #query then
		return 0
	end
	return (score / #target) * 60
end

function FuzzySearch.score(query, text)
	query = normalize(query)
	text = normalize(text)
	if query == "" or text == "" then
		return 0
	end

	if text:find(query, 1, true) then
		return 120 - math.abs(#text - #query)
	end

	local distance = levenshtein(query, text)
	local maxLen = math.max(#query, #text)
	local distanceScore = math.max(0, 100 - ((distance / maxLen) * 100))

	return distanceScore + subsequenceScore(query, text)
end

function FuzzySearch.search(query, entries, limit)
	limit = limit or 20
	local results = {}
	local normalizedQuery = normalize(query)
	if normalizedQuery == "" then
		return {}
	end

	for _, entry in ipairs(entries) do
		local allText = table.concat({
			entry.title or "",
			entry.description or "",
			entry.kind or "",
			table.concat(entry.keywords or {}, " "),
		}, " ")

		local score = FuzzySearch.score(normalizedQuery, allText)
		if score > 25 then
			table.insert(results, {
				entry = entry,
				score = score,
			})
		end
	end

	table.sort(results, function(a, b)
		return a.score > b.score
	end)

	if #results > limit then
		for i = #results, limit + 1, -1 do
			table.remove(results, i)
		end
	end

	return results
end

return FuzzySearch
end

__modules["UI.LoadingOverlay"] = function()
local TweenService = game:GetService("TweenService")

local LoadingOverlay = {}
LoadingOverlay.__index = LoadingOverlay

function LoadingOverlay.new(screenGui, theme, font)
	local self = setmetatable({}, LoadingOverlay)
	self.screenGui = screenGui
	self.theme = theme
	self.font = font
	self.progress = 0
	self:_build()
	return self
end

function LoadingOverlay:_build()
	local colors = self.theme.colors
	self.frame = Instance.new("Frame")
	self.frame.Name = "TailLoadingOverlay"
	self.frame.BackgroundColor3 = colors.background
	self.frame.BackgroundTransparency = 0.06
	self.frame.Size = UDim2.fromScale(1, 1)
	self.frame.Position = UDim2.fromScale(0, 0)
	self.frame.Visible = false
	self.frame.ZIndex = 1000
	self.frame.Parent = self.screenGui

	local title = Instance.new("TextLabel")
	title.Name = "Title"
	title.BackgroundTransparency = 1
	title.Size = UDim2.new(0.7, 0, 0, 42)
	title.Position = UDim2.fromScale(0.15, 0.38)
	title.Font = self.font
	title.TextScaled = true
	title.TextColor3 = colors.text
	title.Text = "Loading Tail UI"
	title.ZIndex = 1001
	title.Parent = self.frame

	self.status = Instance.new("TextLabel")
	self.status.Name = "Status"
	self.status.BackgroundTransparency = 1
	self.status.Size = UDim2.new(0.7, 0, 0, 28)
	self.status.Position = UDim2.fromScale(0.15, 0.46)
	self.status.Font = self.font
	self.status.TextSize = 16
	self.status.TextColor3 = colors.textMuted
	self.status.Text = "Initializing..."
	self.status.ZIndex = 1001
	self.status.Parent = self.frame

	local track = Instance.new("Frame")
	track.Name = "Track"
	track.Size = UDim2.new(0.42, 0, 0, 12)
	track.Position = UDim2.fromScale(0.29, 0.53)
	track.BackgroundColor3 = colors.topbar
	track.BorderSizePixel = 0
	track.ZIndex = 1001
	track.Parent = self.frame

	local trackCorner = Instance.new("UICorner")
	trackCorner.CornerRadius = UDim.new(1, 0)
	trackCorner.Parent = track

	self.fill = Instance.new("Frame")
	self.fill.Name = "Fill"
	self.fill.Size = UDim2.new(0, 0, 1, 0)
	self.fill.BackgroundColor3 = colors.accent
	self.fill.BorderSizePixel = 0
	self.fill.ZIndex = 1002
	self.fill.Parent = track

	local fillCorner = Instance.new("UICorner")
	fillCorner.CornerRadius = UDim.new(1, 0)
	fillCorner.Parent = self.fill
end

function LoadingOverlay:show(initialText)
	self.status.Text = initialText or "Starting..."
	self.progress = 0
	self.fill.Size = UDim2.new(0, 0, 1, 0)
	self.frame.Visible = true
end

function LoadingOverlay:setProgress(value, text)
	self.progress = math.clamp(value, 0, 1)
	if text then
		self.status.Text = text
	end

	TweenService:Create(
		self.fill,
		TweenInfo.new(0.18, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
		{ Size = UDim2.new(self.progress, 0, 1, 0) }
	):Play()
end

function LoadingOverlay:step(index, total, text)
	total = math.max(total, 1)
	self:setProgress(index / total, text)
end

function LoadingOverlay:hide()
	if not self.frame.Visible then
		return
	end

	local tween = TweenService:Create(
		self.frame,
		TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
		{ BackgroundTransparency = 1 }
	)
	tween:Play()
	tween.Completed:Wait()

	self.frame.Visible = false
	self.frame.BackgroundTransparency = 0.06
end

function LoadingOverlay:destroy()
	if self.frame then
		self.frame:Destroy()
	end
end

return LoadingOverlay
end

__modules["UI.Window"] = function()
local CoreGui = game:GetService("CoreGui")
local Players = game:GetService("Players")
local TweenService = game:GetService("TweenService")
local UserInputService = game:GetService("UserInputService")

local function loadModule(moduleName, fallbackLoader)
	local env = getfenv and getfenv() or _G
	local custom = (env and env.__TAILUI_REQUIRE) or _G.__TAILUI_REQUIRE
	if type(custom) == "function" then
		return custom(moduleName)
	end
	return fallbackLoader()
end

local FuzzySearch = loadModule("UI.FuzzySearch", function()
	return require(script.Parent.FuzzySearch)
end)
local LoadingOverlay = loadModule("UI.LoadingOverlay", function()
	return require(script.Parent.LoadingOverlay)
end)

local Window = {}
Window.__index = Window

local Tab = {}
Tab.__index = Tab

local Section = {}
Section.__index = Section

local function readGlobal(name)
	local env = getfenv and getfenv() or _G
	if env and env[name] ~= nil then
		return env[name]
	end
	return _G[name]
end

local function pickGuiParent(fallback)
	if typeof(fallback) == "Instance" then
		return fallback
	end

	local gethui = readGlobal("gethui")
	if type(gethui) == "function" then
		local ok, result = pcall(gethui)
		if ok and typeof(result) == "Instance" then
			return result
		end
	end

	local player = Players.LocalPlayer
	if player then
		local playerGui = player:FindFirstChildOfClass("PlayerGui")
		if playerGui then
			return playerGui
		end
	end

	return CoreGui
end

local function protectExecutorGui(gui)
	local syn = readGlobal("syn")
	if type(syn) == "table" and type(syn.protect_gui) == "function" then
		pcall(syn.protect_gui, gui)
	end

	local protectgui = readGlobal("protectgui")
	if type(protectgui) == "function" then
		pcall(protectgui, gui)
	end
end

local function token(theme, path, fallback)
	local current = theme
	for part in tostring(path):gmatch("[^%.]+") do
		if type(current) ~= "table" then
			return fallback
		end
		current = current[part]
	end
	if current == nil then
		return fallback
	end
	return current
end

local function corner(target, radius)
	local object = Instance.new("UICorner")
	object.CornerRadius = UDim.new(0, radius)
	object.Parent = target
	return object
end

local function stroke(target, color, transparency)
	local object = Instance.new("UIStroke")
	object.Thickness = 1
	object.Color = color
	object.Transparency = transparency or 0
	object.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
	object.Parent = target
	return object
end

local function clearNonLayoutChildren(parent)
	for _, child in ipairs(parent:GetChildren()) do
		if not child:IsA("UIListLayout") and not child:IsA("UIPadding") then
			child:Destroy()
		end
	end
end

local function flatten(values)
	local out = {}
	for _, value in ipairs(values) do
		table.insert(out, tostring(value))
	end
	return out
end

local function setTreeZIndex(root, zIndex)
	if not root then
		return
	end
	if root:IsA("GuiObject") then
		root.ZIndex = zIndex
	end
	for _, child in ipairs(root:GetChildren()) do
		if child:IsA("GuiObject") then
			child.ZIndex = zIndex
		end
	end
end

function Window.new(context, options)
	options = options or {}

	local self = setmetatable({}, Window)
	self.context = context
	self.options = options
	self.logger = context.logger
	self.safeCall = context.safeCall
	self.themeManager = context.themeManager
	self.iconRegistry = context.iconRegistry
	self.fontRegistry = context.fontRegistry
	self.config = context.config

	self.connections = {}
	self.themeBindings = {}
	self.tabs = {}
	self.searchEntries = {}
	self.tagIndex = 0
	self.destroyed = false
	self.minimized = false
	self.maximized = false

	self.themeName = options.theme or self.config.theme.active
	self.theme = self.themeManager:get(self.themeName) or self.themeManager:getActiveTheme() or {}
	self.font = self.fontRegistry:resolve(options.font or self.config.fonts.default, "ui-sans")
	self.boldFont = self.fontRegistry:resolve("ui-sans-semibold", "ui-sans")

	if options.searchEnabled == nil then
		self.searchEnabled = self.config.internal.searchEnabled
	else
		self.searchEnabled = options.searchEnabled
	end

	self.topbarHeight = options.topbarHeight or 42
	self.sidebarWidth = options.sidebarWidth or 188
	self.mobileSidebarWidth = options.mobileSidebarWidth or 148

	self:_build()
	self:_watchTheme()
	self:_applyTheme(self.theme)
	self:_applyResponsive()
	self:setSearchEnabled(self.searchEnabled)

	return self
end

function Window:_connect(signal, callback)
	local connection = signal:Connect(callback)
	table.insert(self.connections, connection)
	return connection
end

function Window:_safe(scope, callback, onFailure)
	if type(callback) ~= "function" then
		return function() end
	end

	if self.safeCall then
		return self.safeCall:wrap(scope, callback, onFailure)
	end

	return function(...)
		local ok, err = pcall(callback, ...)
		if not ok then
			if onFailure then
				onFailure(err)
			end
			warn(("[TailUI] callback fail in %s: %s"):format(scope, tostring(err)))
		end
	end
end

function Window:_bindTheme(instance, propertyName, path, fallback)
	table.insert(self.themeBindings, {
		instance = instance,
		property = propertyName,
		path = path,
		fallback = fallback,
	})

	local value = token(self.theme, path, fallback)
	if value ~= nil then
		instance[propertyName] = value
	end
end

function Window:_applyTheme(theme)
	self.theme = theme or self.theme
	for _, item in ipairs(self.themeBindings) do
		if item.instance and item.instance.Parent then
			local value = token(self.theme, item.path, item.fallback)
			if value ~= nil then
				item.instance[item.property] = value
			end
		end
	end

	if self.activeTab then
		self:_activateTab(self.activeTab)
	end
end

function Window:_watchTheme()
	self.themeConnection = self.themeManager:onChanged(function(name, theme)
		self.themeName = name
		self:_applyTheme(theme)
	end)
end

function Window:_build()
	local parent = pickGuiParent(self.options.parent)
	local windowConfig = self.config.window
	local size = self.options.size or windowConfig.size
	local minimum = self.options.minimumSize or windowConfig.minimumSize

	self.baseSize = Vector2.new(size.width, size.height)
	self.minimumSize = Vector2.new(minimum.width, minimum.height)

	self.screenGui = Instance.new("ScreenGui")
	self.screenGui.Name = "TailUI_ScreenGui"
	self.screenGui.ResetOnSpawn = false
	self.screenGui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
	self.screenGui.IgnoreGuiInset = true
	self.screenGui.Parent = parent
	protectExecutorGui(self.screenGui)

	local showLoading = self.config.internal.showLoading ~= false
	if self.options.loading and self.options.loading.enabled == false then
		showLoading = false
	end
	if showLoading then
		self.loadingOverlay = LoadingOverlay.new(self.screenGui, self.theme, self.boldFont)
		self.loadingOverlay:show("Initializing Tail UI...")
		self.loadingOverlay:step(1, 5, "Creating window")
	end

	self.main = Instance.new("Frame")
	self.main.Name = "Main"
	self.main.AnchorPoint = Vector2.new(0.5, 0.5)
	self.main.Position = UDim2.fromScale(0.5, 0.5)
	self.main.Size = UDim2.fromOffset(self.baseSize.X, self.baseSize.Y)
	self.main.ClipsDescendants = true
	self.main.BorderSizePixel = 0
	self.main.Parent = self.screenGui
	corner(self.main, token(self.theme, "rounding.window", 16))
	stroke(self.main, token(self.theme, "colors.border", Color3.fromRGB(170, 176, 188)), 0.15)
	self:_bindTheme(self.main, "BackgroundColor3", "colors.surface", Color3.fromRGB(250, 251, 253))

	self.openButton = Instance.new("TextButton")
	self.openButton.Name = "TopMenuOpenButton"
	self.openButton.Size = UDim2.fromOffset(154, 34)
	self.openButton.Position = UDim2.fromOffset(14, 14)
	self.openButton.Font = self.boldFont
	self.openButton.TextSize = 13
	self.openButton.Text = self.iconRegistry:resolve("maximize") .. "  Open"
	self.openButton.BorderSizePixel = 0
	self.openButton.Visible = false
	self.openButton.Parent = self.screenGui
	corner(self.openButton, 10)
	stroke(self.openButton, token(self.theme, "colors.border", Color3.fromRGB(170, 176, 188)), 0.2)
	self:_bindTheme(self.openButton, "BackgroundColor3", "colors.topbar", Color3.fromRGB(230, 235, 240))
	self:_bindTheme(self.openButton, "TextColor3", "colors.text", Color3.fromRGB(22, 22, 24))

	if self.loadingOverlay then
		self.loadingOverlay:step(2, 5, "Building topbar")
	end

	self:_buildTopbar()
	self:_buildBody()
	self:_buildErrorLabel()
	self:_bindResizeAndDrag()

	if self.loadingOverlay then
		self.loadingOverlay:step(3, 5, "Binding responsive mode")
	end

	self:_bindViewport()

	if self.loadingOverlay then
		self.loadingOverlay:step(4, 5, "Preparing default tab")
	end

	local home = self:addTab({ id = "home", title = "Home", icon = "folder" })
	home:addLabel({
		text = "Tail UI initialized.",
		description = "Use addTab/addSection and the components API.",
	})

	if self.loadingOverlay then
		self.loadingOverlay:step(5, 5, "Ready")
		task.wait(0.1)
		self.loadingOverlay:hide()
	end
end

function Window:_buildTopbar()
	self.topbar = Instance.new("Frame")
