	toggleButton.TextSize = 14
	toggleButton.BackgroundTransparency = 1
	toggleButton.Parent = section.frame.Header

	local opened = true
	local function sync()
		section.content.Visible = opened
		toggleButton.Text = opened and "v" or ">"
